function colorEncodeIdAndPack(o,r){r=r||[];var d=256,n=255,c=Math.floor(o/d/d/d)/n,t=Math.floor(o/d/d)%d/n,a=Math.floor(o/d)%d/n,o=o%d/n;return r[0]=256*c*255+255*t,r[1]=256*a*255+255*o,r}function colorDecodeId(o){var r=0,d=256,n=255;return(r+=Math.round(o[0]*d*d*d*n))+Math.round(o[1]*d*d*n)+Math.round(o[2]*d*n)+Math.round(o[3]*n)}export{colorEncodeIdAndPack,colorDecodeId};